module register_16bit(
    input [15:0] d,
    input clk,
    input en,
    input clr,
    output reg [15:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (clr)
            q <= 16'b0;
        else if (en)
            q <= d;
    end

endmodule
